
import { ref, onMounted } from 'vue';
import { getLearningMachineVersion } from '@/utils'
export default {
  name: 'Battery',
  components: {
  },

  setup() {
    const version = ref(1)
    onMounted(async () => {
      const { version: vers } = await getLearningMachineVersion()
      version.value = vers
    })

    return {
      version
    }
  }
}
