import ApiService, { ResponseType } from '@/api/api';

export default {
  // 登录后端接口
  login(obj: any): ResponseType<string> {
    return ApiService.post('/parent/api/v1/code/login', obj);
  },
  // 获取家庭详细信息
  getFamilyInfo(obj: any): ResponseType<string> {
    return ApiService.post('/parent/api/v1/family/invite/family-info', obj);
  },
  // 校验邀请链接是否合法
  checkInviteUrl(obj: any): ResponseType<string> {
    return ApiService.post('/parent/api/v1/family/invite-url/check', obj);
  },
  // 立即加入
  joinFamily(obj: any): ResponseType<string> {
    return ApiService.post('/parent/api/v1/family/invite/join', obj);
  }
}
