
import { computed, ref, ComponentInternalInstance, getCurrentInstance, onMounted, reactive, nextTick } from 'vue';
import sensors from '../../utils/sensors'
import { Toast, Popup } from "vant"
import { useRoute } from 'vue-router'
import api from './api'
import { isEdstars } from '@/utils/url';
import { banScale } from './utils'
export default {
  name: 'Login',
  components: {
    Popup,
  },
  setup() {
    const current: ComponentInternalInstance | null = getCurrentInstance()
    const globalProperties = (current as ComponentInternalInstance).appContext.config.globalProperties
    const $message = globalProperties.$message
    const $route = useRoute()
    const domain = location.origin


    const smsCodeText = ref('获取验证码')
    const errMessage = ref('')
    const phone = ref('')
    const smscode = ref('')
    const disableBtn = ref(false)
    const checked = ref(false)
    const code = ref('')
    const isLoginSuccess = ref(false)
    const isJoined = ref(false)
    const login_result = ref('')
    const join_result = ref('')
    const userProtocol = `${domain}/mbxpp/#/xUserProtocol`
    const userPrivacy = computed(() => {
      const ios = !!navigator.userAgent.match(/\(i[^;]+;( U;)? CPU.+Mac OS X/)
      
      if (ios) {
        return `${domain}/mbxpp/#/xInfoIOS`
      } else {
        return `${domain}/mbxpp/#/xInfoAndroid`
      }
    })

    const showBottom = ref(false)
    const isValidUrl = ref(true)
    const familyInfo = reactive({
      family_name: '',
      manager_avatar_url: ''
    })
    
    const handleclearMessage = () => {
      errMessage.value = ""
    }
    const phoneChecked = () => {
      return /^1[3-9]\d{9}$/.test(phone.value);
    }
    const codeChecked = () => {
      return /\d{6}$/.test(smscode.value);
    }
    const phoneTips = computed(() => {
      if (phoneChecked()) {
        return ""
      }
      if (!phone.value) {
        return ""
      }
      return "*请输入正确的手机号"
    })
    const codeTips = computed(() => {
      if (codeChecked()) {
        return ""
      }
      if (!smscode.value) {
        return ""
      }
      return "*请输入正确的验证码"
    })
    const loginbtndisable = computed(() => (!phoneChecked() || !codeChecked() || smscode.value.length !== 6) && !window.localStorage.getItem('tal_token'))
    // 获取验证码
    const handlegetSMSCode = () => {
      if (!phoneChecked() || disableBtn.value) {
        return
      }
      Toast.loading({
        message: "加载中..."
      })
      let payload = {
        data: {
          phone: phone.value.trim(),
          phone_code: "86",
          send_type: 1,
        },
        success: (res: any) => {
          Toast.clear()
          if (res.errcode == 0) {
            startSmsClock()
          } else if (+res.errcode == 11021) {
            showSlide("sendSMSCodeLogin", payload)
          } else {
            errMessage.value = res.errmsg
            smsCodeText.value = "重新获取"
          }
        },
        fail: (error: any) => {
          Toast.clear()
          console.log(error)
        },
      }
      window.TAL_UC.sendSMSCodeLogin(payload)
    }
    const startSmsClock = () => {
      let clockTime = 60
      let timer: number | null | undefined = null
      timer = setInterval(() => {
        clockTime--
        disableBtn.value = true
        smsCodeText.value = `${clockTime}s后重发`
        if (clockTime === 0) {
          smsCodeText.value = "重新获取"
          timer && clearInterval(timer)
          disableBtn.value = false
        }
      }, 1000)
    }
    // 登录 or 立即加入 or 下载学而思智能APP
    const handleLogin = async () => {
      // 登录
      if (!isLoginSuccess.value) {
        // 判断链接是否有效
        await checkUrl()
        if (isValidUrl.value === false) {
          return
        }
        if (!checked.value) {
          // $message("请勾选协议")
          showBottom.value = true
          return
        }
        Toast.loading({
          message: "加载中..."
        })
        const params = {
          data: {
            phone: phone.value.trim(), // 地区不同手机号码规则不同
            phone_code: 86, // 手机地区码
            sms_code: smscode.value.trim(), // 短信验证码
          },
          success: (res: any) => {
            const { data, errcode, errmsg } = res
            Toast.clear()
            switch (+errcode) {
              case 0:
                // 登录成功
                code.value = data.code
                getLoginCode()
                break
              case 11021:
                // 展示滑块
                showSlide("loginSms", params)
                break
              default:
                errMessage.value = errmsg
                login_result.value = errmsg
                sensors.track('join_family_login_click', {
                  login_result: login_result.value
                })
            }
          },
          fail: (error: any) => {
            Toast.clear()
            login_result.value = error
            sensors.track('join_family_login_click', {
              login_result: login_result.value
            })
            console.log(error)
          },
        }
        window.TAL_UC.loginSms(params)
      // 立即加入
      } else if (!isJoined.value) {
        // 判断链接是否有效
        await checkUrl()
        if (isValidUrl.value === false) {
          return
        }
        Toast.loading({
          message: "加载中..."
        })
        try {
          const { data } = await api.joinFamily({ family_id: $route.query.family_id, invite_code: $route.query.invite_code, token: window.localStorage.getItem('tal_token')})
          join_result.value = data.errmsg
          if (data.errcode === 0) {
            isJoined.value = true
            join_result.value = '成功'
            $message('加入成功')
          // token过期
          } else if (data.errcode === 29999) {
            $message(data.errmsg)
            console.log(loginbtndisable.value, '111111------')
            window.localStorage.removeItem('tal_token')
            console.log(loginbtndisable.value, '222222------')
            isLoginSuccess.value = false
            console.log(loginbtndisable.value, '3333333------')
            nextTick(() => {
              checked.value = false
              smscode.value = ''
              phone.value = ''
              console.log(loginbtndisable.value, '4444444------')
            })
          } else {
            $message(data.errmsg)
          }
          Toast.clear()
        } catch (e: any) {
          Toast.clear()
          $message(e.message || '网络失败，请重新申请')
          join_result.value = e.message
        } finally {
          sensors.track('join_family_join_click', {
            join_result: join_result.value
          })
        }
      } else {
        sensors.track('join_family_download_click', {})
        window.location.href = `${domain}/mbxpp/#/downloadApp`
      }
    }
    const showSlide = (slideCallback: any, payload: any) => {
      window.TAL_UC.showSlide({
        slideCallback,
        slideParams: payload,
        failCallback: (error: any) => {
          $message(error.errmsg)
        },
      })
    }
    const getLoginCode = async () => {
      let res: any = { data: {} }
      const clientId = isEdstars() ? '551203' : '551202'
      try {
        res = await api.login({
          code: code.value,
          client_id: clientId
        })
        const { data } = res
        if (data.errcode === 0 && data.data.tal_token) {
          window.localStorage.setItem("tal_token", data.data.tal_token)
          $message("登录成功")
          isLoginSuccess.value = true
          login_result.value = '成功'
        } else {
          $message(data.errmsg)
          login_result.value = data.errmsg
          // errMessage.value = "*验证码错误或失效"
        }
      } catch (e: any) {
        login_result.value = e.message
        $message(e.message || "网络异常，请重新登录")
      } finally {
        smsCodeText.value = "重新获取"
        disableBtn.value = false
        sensors.track('join_family_login_click', {
          login_result: login_result.value
        })
      }
    }
    const agreeProtocol = () => {
      checked.value = true
      showBottom.value = false
      handleLogin()
    }
    // 判断链接是否有效
    const checkUrl = async () => {
      try {
        const { data } = await api.checkInviteUrl({ family_id: $route.query.family_id, invite_code: $route.query.invite_code })
        if (data.errcode !== 0) {
          isValidUrl.value = false
        }
      } catch (e: any) {
        $message(e.message || "网络异常")
      }
    }
    onMounted(async () => {
      banScale()
      // 判断链接是否有效
      await checkUrl()
      sensors.track('join_family_url_click', {
        valid: isValidUrl.value ? 1 : 0
      })
      if (isValidUrl.value === false) {
        return
      }
      // 判断是否已登录
      if (window.localStorage.getItem('tal_token')) {
        isLoginSuccess.value = true
      } else {
        // 先都采用沙盒环境
        const curenv = (process.env.VUE_APP_NODE_ENV === "production" || process.env.VUE_APP_NODE_ENV === "gray") ? "production" : "sandbox"
        window.TAL_UC.rankConfig({
          // "client-id": "551202", // client-id由平台发放权限码，接入之前向平台申请
          "client-id": isEdstars() ? '551203' : '551202',
          env: curenv, // 环境标识： 'sandbox': 沙箱环境； 'production': 线上生产环境；默认为生产(备注，引入npm包才需要该字段)
        })
        // 滑块配置
        window.TAL_UC.configNVC({
          renderToEle: "#captcha",
          isH5: true,
        })
      }
      try {
        const { data }: any = await api.getFamilyInfo({ family_id: $route.query.family_id, invite_code: $route.query.invite_code })
        if (data.errcode === 0 && data.data) {
          familyInfo.family_name = data.data.family_name
          familyInfo.manager_avatar_url = data.data.manager_avatar_url
        } else {
          $message(data.errmsg || '获取家庭信息失败')
        }
      } catch (e: any) {
        $message(e.message || "网络异常")
      }   
    })
    return {
      smsCodeText,
      errMessage,
      phone,
      smscode,
      phoneTips,
      codeTips,
      familyInfo,
      isLoginSuccess,
      userProtocol,
      userPrivacy,
      checked,
      loginbtndisable,
      showBottom,
      isValidUrl,
      isJoined,
      handleclearMessage,
      handlegetSMSCode,
      handleLogin,
      phoneChecked,
      agreeProtocol
    }
  }
}
